// ── Đọc payload từ BE ──
const body = $input.first().json.body ?? $input.first().json;
const endpoints = body.endpoints;

if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload thiếu mảng endpoints hoặc rỗng.');
}

// ── Xây dựng danh sách endpoint cho prompt ──
const lines = endpoints.map((ep, i) => {
  const deps = ep.dependsOnEndpointIds?.length > 0
    ? ` | DependsOn: [${ep.dependsOnEndpointIds.join(', ')}]`
    : '';
  const auth = ep.isAuthRelated ? ' [AUTH]' : '';
  const paramRefs = ep.parameterSchemaRefs?.length > 0
    ? ` | ParamSchemas: ${ep.parameterSchemaRefs.join(', ')}`
    : '';
  const respRefs = ep.responseSchemaRefs?.length > 0
    ? ` | ResponseSchemas: ${ep.responseSchemaRefs.join(', ')}`
    : '';
  return `${i + 1}. [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}${auth}${deps}${paramRefs}${respRefs}`;
}).join('\n');

// ── System prompt ──
const systemPrompt = `You are an expert REST API testing engineer specializing in test execution order design.
Your goal is to determine the optimal sequential order for testing a list of REST API endpoints,
minimizing test failures caused by wrong execution order.`;

// ── User prompt ──
const userPrompt = `Analyze and order the following API endpoints for sequential automated testing.

=== ORDERING RULES (apply in priority order) ===
1. [AUTH] endpoints (login, token, authenticate, register) must run FIRST (lowest orderIndex)
2. Resource CREATION (POST) must come before READ (GET), UPDATE (PUT/PATCH), and DELETE for the same resource
3. Respect explicit DependsOn relationships — if endpoint A depends on endpoint B, B must have a lower orderIndex
4. DELETE operations must run LAST for each resource
5. Consider resource hierarchy from path: /users before /users/{id}/posts
6. Schema relationships: if endpoint B uses a schema produced by endpoint A, A runs before B

=== ENDPOINTS TO ORDER ===
${lines}

=== RESPONSE FORMAT ===
Respond with ONLY a raw JSON object. No markdown, no code fences, no explanation outside JSON.

{
  "orderedEndpoints": [
    {
      "endpointId": "<exact UUID from input>",
      "httpMethod": "<exact HTTP method from input>",
      "path": "<exact path from input>",
      "orderIndex": <0-based integer, 0 = first to run>,
      "dependsOnEndpointIds": ["<UUID of endpoints that must run before this>"],
      "reasonCodes": ["<one or more of: AUTH_FIRST, CREATE_BEFORE_READ, CREATE_BEFORE_UPDATE, CREATE_BEFORE_DELETE, DEPENDENCY, CRUD_ORDER, SCHEMA_DEPENDENCY, HIERARCHY>"],
      "isAuthRelated": <true or false>
    }
  ],
  "reasoning": "<one paragraph summarizing the overall ordering strategy>",
  "llmModel": "gpt-4o"
}

Ensure every endpoint from the input appears exactly once in orderedEndpoints. OrderIndex values must be unique integers starting from 0.`;

// ── Build OpenAI request body ──
const openAiBody = {
  model: 'gpt-4o',
  temperature: 0.1,
  max_tokens: 4096,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    openAiBody,
    originalBody: body
  }
}];

// ── Đọc response từ OpenAI ──
const response = $input.first().json;

if (response.error) {
  throw new Error(`OpenAI API error: ${response.error.message ?? JSON.stringify(response.error)}`);
}

const rawContent = response.choices?.[0]?.message?.content;
if (!rawContent) {
  throw new Error('OpenAI trả về response rỗng hoặc không đúng format.');
}

// ── Loại bỏ markdown code block nếu có ──
let cleaned = rawContent.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
}

// ── Parse JSON ──
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Không parse được JSON từ LLM. Error: ${e.message}\nRaw (500 chars): ${cleaned.substring(0, 500)}`);
}

const ordered = parsed.orderedEndpoints;
if (!Array.isArray(ordered) || ordered.length === 0) {
  throw new Error('LLM response thiếu mảng orderedEndpoints hoặc rỗng.');
}

// ── Chuẩn hóa orderIndex thành 0-based liên tiếp ──
ordered.sort((a, b) => (a.orderIndex ?? 0) - (b.orderIndex ?? 0));
ordered.forEach((ep, i) => { ep.orderIndex = i; });

// ── Đảm bảo các field bắt buộc tồn tại ──
ordered.forEach(ep => {
  if (!ep.endpointId) throw new Error('Endpoint thiếu endpointId trong LLM response.');
  ep.dependsOnEndpointIds = ep.dependsOnEndpointIds ?? [];
  ep.reasonCodes = ep.reasonCodes ?? [];
  ep.isAuthRelated = ep.isAuthRelated ?? false;
});

return [{
  json: {
    orderedEndpoints: ordered,
    reasoning: parsed.reasoning ?? '',
    llmModel: parsed.llmModel ?? 'gpt-4o'
  }
}];
